  "questionProse": [
    "निम्नलिखित HTML में `<a>` लिंक के टेक्स्ट का पिक्सेल आकार क्या है?"
  ],
  "explanationProse": [
    "`<a>` के लिए `font-size` की गणना 5px होती है: 40px (body) * 50% (nav) = 20px, फिर 20px * 25% = 5px."
  ]
}
